/**
 * Capability catalog for the MEO nodes.
 *
 * Must stay value-for-value in sync with the gateway's MeoCmd.java and the
 * firmware's Meo3_Cmd.h. The id range encodes the action — there is no verb
 * field — so the kind is derived from the id rather than stored per entry.
 */
module.exports = (function() {
    "use strict";

    var EVENT_BASE = 0xE000;
    var READ_BASE  = 0xF000;
    var WRITE_BASE = 0xFF00;

    // Labels are what a child reads in the palette, not the constant name.
    var LABELS = {
        0x0001: "Generic command",
        0x0002: "Write",
        0x0003: "Read",
        0x0004: "Run",
        0x0005: "Run with value",
        0x0006: "Stop",

        0xE000: "Generic event",
        0xE001: "Button",

        0xF000: "Generic reading",
        0xF001: "Temperature",
        0xF002: "Humidity",
        0xF003: "Pressure",
        0xF004: "CO2",
        0xF005: "Fine dust (PM2.5)",
        0xF006: "Distance",

        0xFF00: "Generic output",
        0xFF01: "Built-in LED",
        0xFF02: "RGB LED",
        0xFF03: "Buzzer",
        0xFF04: "Motor",
        0xFF05: "Servo"
    };

    // Mirrors MeoCmd.isEvent / isRead / isWrite.
    function kindOf(id) {
        if (id >= WRITE_BASE) { return "write"; }
        if (id >= READ_BASE)  { return "read"; }
        if (id >= EVENT_BASE) { return "event"; }
        return "command";
    }

    function labelOf(id) {
        return LABELS[id] || ("Capability 0x" + id.toString(16).toUpperCase());
    }

    function entry(id) {
        return { id: id, label: labelOf(id), kind: kindOf(id) };
    }

    return {
        kindOf: kindOf,
        labelOf: labelOf,

        /** The whole catalog, for a device that declared nothing usable. */
        list: function() {
            return Object.keys(LABELS).map(Number).map(entry);
        },

        /**
         * Capabilities that may be commanded. Events are device→gateway only;
         * MeoControlHandler rejects them outright, so they never reach the picker.
         */
        commandable: function(ids) {
            return (ids || [])
                .map(Number)
                .filter(function(id) { return kindOf(id) !== "event"; })
                .map(entry);
        }
    };
}());
